INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (10, 0, 107611, 11, "シズルさまにエリコさま、\nどうかされたのですか？", 0, 19050041, 1, 905, 0.5, 0);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "", 0, 91, "", "", 19050042, "", 905, "", "");
