INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (10, 0, 115711, 11, "ここメルクリゾートではプールサイドで\nたい焼きを売る怪人の噂がある。", 0, 19230017, 1, 923, 0.5, 0);
