INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (10, 0, 107911, 11, "こんなに人がいっぱいいる商機、\n見逃すわけにはいかないにゃ！", 0, 19440038, 1, 944, 1, 0);
